// Rotation Matix functions
vector<double> euler2quat(double phi, double theta, double psi){
    double q0 = cos(psi/2)*cos(theta/2)*cos(phi/2)+sin(psi/2)*sin(theta/2)*sin(phi/2);
    double q1 = cos(psi/2)*cos(theta/2)*sin(phi/2)-sin(psi/2)*sin(theta/2)*cos(phi/2);
    double q2 = cos(psi/2)*sin(theta/2)*cos(phi/2)+sin(psi/2)*cos(theta/2)*sin(phi/2);
    double q3 = sin(psi/2)*cos(theta/2)*cos(phi/2)-cos(psi/2)*sin(theta/2)*sin(phi/2);

    vector<double> q = {q0,q1,q2,q3};
    return q;
};

vector<vector<double>> quat2DCM(double q0, double q1, double q2, double q3){
    vector<vector<double>> R = {{2*pow(q0,2)+2*pow(q1,2)-1, 2*q1*q2+2*q0*q3, 2*q1*q3-2*q0*q2},
                                {2*q1*q2-2*q0*q3, 2*pow(q0,2)+2*pow(q2,2)-1, 2*q2*q3+2*q0*q1},
                                {2*q1*q3+2*q0*q2, 2*q2*q3-2*q0*q1, 2*pow(q0,2)+2*pow(q3,2)-1}};
    return R;               
};

vector<double> rotateQuaternionRate(vector<double> q, vector<vector<double>> omega){
    vector<vector<double>> M1 = {{-q[1], -q[2], -q[3]},
                                 {q[0], -q[3], q[2]},
                                 {q[3], q[0], -q[1]},
                                 {-q[2], q[1], q[0]}};
    vector<vector<double>> result = mat_mul(matrixTimesScaler(0.5, M1), omega);

    vector<double> output = {result[0][0], result[1][0], result[2][0], result[3][0]};
    return output;
}

// Parse CSV file and return drag table
std::vector<DragEntry> parseDragCSV(const std::string& filename) {
    std::vector<DragEntry> table;
    std::ifstream file(filename);
    std::string line;
    // Skip header
    std::getline(file, line);
    while (std::getline(file, line)) {
        std::stringstream ss(line);
        std::string cell;
        std::vector<std::string> cells;
        while (std::getline(ss, cell, ',')) {
            cells.push_back(cell);
        }
        if (cells.size() >= 13) {
            try {
                double mach = std::stod(cells[0]);
                double cd = std::stod(cells[2]);
                double cnalpha = std::stod(cells[12]);
                table.push_back({mach, cd, cnalpha});
                if (mach > 3) break;
            } catch (...) {
                // skip invalid rows
            }
        }
    }
    return table;
}

// Linear interpolation for drag lookup
std::pair<double, double> lookupDrag(double mach, const std::vector<DragEntry>& table) {
    if (table.empty()) {
        return {0, 0};
    }
    // If mach is out of bounds, clamp to ends
    if (mach <= table.front().mach) {
        return {table.front().cd, table.front().cnalpha};
    }
    if (mach >= table.back().mach) {
        return {table.back().cd, table.back().cnalpha};
    }
    // Find interval
    for (size_t i = 1; i < table.size(); ++i) {
        if (mach < table[i].mach) {
            double m0 = table[i-1].mach;
            double m1 = table[i].mach;
            double cd0 = table[i-1].cd;
            double cd1 = table[i].cd;
            double cn0 = table[i-1].cnalpha;
            double cn1 = table[i].cnalpha;
            double t = (mach - m0) / (m1 - m0);
            double cd = cd0 + t * (cd1 - cd0);
            double cnalpha = cn0 + t * (cn1 - cn0);
            return {cd, cnalpha};
        }
    }
    // fallback
    return {table.back().cd, table.back().cnalpha};
}


