double calculateSoS(double gamma, double R, double T){
    double SoS = sqrt(gamma*R*T);
    return SoS;
}

double calculateMachNumber(double V, double SoS){
    double M = V/SoS;
    return M;
}

vector<vector<double>> calculateH(uint sensor_id, vector<vector<double>> states){
    /*
    sensor_id - Sensor ID to determine which jacobian to use
    states - to calculate jacobian
    H is output


    Sensor IDs:
    - accelerometer/gyro - 0
    - high G accelerometer - 1
    - pressure/temperature - 2
    

    Measurement vector: [a_x, a_y, a_z, p, q, r, P, T]^T
    */

    

    double P_u = states[2][0];

    vector<vector<double>> a_w({{states[6][0]},{states[7][0]},{states[8][0]+gravity}});

    // double a_x = states[6][0];
    // double a_y = states[7][0];
    // double a_z = states[8][0];

    double q0 = states[9][0];
    double q1 = states[10][0];
    double q2 = states[11][0];
    double q3 = states[12][0];

    double q0_dot = states[13][0];
    double q1_dot = states[14][0];
    double q2_dot = states[15][0];
    double q3_dot = states[16][0];


    vector<vector<double>> a_b = mat_mul(quat2DCM(q0,q1,q2,q3),a_w);
    vector<vector<double>> R = quat2DCM(q0,q1,q2,q3);

    vector<vector<double>> H;

    switch (sensor_id){
        case 3:
        H = vector<vector<double>>(6, vector<double>(states.size(), 0));
        for (int i = 0; i<3; i++){
            for (int j = 0; j<3; j++){
                H[i][j+6] = R[i][j];
            }
        }
        // H[0][6] = R[0][0];
        // H[0][7]= H[1][7] = H[2][8] = 1;


        // H[0][9] = 2*q2*gravity;
        // H[0][10] = -2*q3*gravity;
        // H[0][11] = 2*q0*gravity;
        // H[0][12] = -2*q1*gravity;

        // H[1][9] = -2*q1*gravity;
        // H[1][10] = -2*q0*gravity;
        // H[1][11] = -2*q3*gravity;
        // H[1][12] = -2*q2*gravity;

        // H[2][9] = 2*q0*gravity;
        // H[2][10] = -2*q1*gravity;
        // H[2][11] = -2*q2*gravity;
        // H[2][12] = 2*q3*gravity;


        // Jacobian for p
        H[3][9] = 2*q1_dot;
        H[3][10] = -2*q0_dot;
        H[3][11] = -2*q3_dot;
        H[3][12] = 2*q2_dot;
        H[3][13] = -2*q1;
        H[3][14] = 2*q0;
        H[3][15] = 2*q3;
        H[3][16] = -2*q2;

        // Jacobian for q
        H[4][9] = 2*q2_dot;
        H[4][10] = 2*q3_dot;
        H[4][11] = -2*q0_dot;
        H[4][12] = -2*q1_dot;
        H[4][13] = -2*q2;
        H[4][14] = -2*q3;
        H[4][15] = 2*q0;
        H[4][16] = 2*q1;

        // Jacobian for r
        H[5][9] = 2*q3_dot;
        H[5][10] = -2*q2_dot;
        H[5][11] = 2*q1_dot;
        H[5][12] = -2*q0_dot;
        H[5][13] = -2*q3;
        H[5][14] = 2*q2;
        H[5][15] = -2*q1;
        H[5][16] = 2*q0;
        break;



        case 5:
        H = vector<vector<double>>(3, vector<double>(states.size(), 0));
        for (int i = 0; i<3; i++){
            for (int j = 0; j<3; j++){
                H[i][j+6] = R[i][j];
            }
        }

        // H[0][9] = 2*q2*gravity;
        // H[0][10] = -2*q3*gravity;
        // H[0][11] = 2*q0*gravity;
        // H[0][12] = -2*q1*gravity;

        // H[1][9] = -2*q1*gravity;
        // H[1][10] = -2*q0*gravity;
        // H[1][11] = -2*q3*gravity;
        // H[1][12] = -2*q2*gravity;

        // H[2][9] = 2*q0*gravity;
        // H[2][10] = -2*q1*gravity;
        // H[2][11] = -2*q2*gravity;
        // H[2][12] = 2*q3*gravity;
        break;

        case 2:
        H = vector<vector<double>>(2, vector<double>(states.size(), 0));
        // Temperature
        H[1][2] = -L;
        
        // Pressure
        H[0][2] = P0*(-gravity/(R_air*T0))*pow((1-(L*P_u/T0)),(gravity/(R_air*L)-1));
        break;


    }
    return H;

}

vector<vector<double>> calculateHx(uint sensor_id, vector<vector<double>> states){
    /*

    Calculate the expected sensor values to use for the resudual


    Sensor IDs:
    - accelerometer/gyro - 0
    - high_G accelerometer - 1
    - pressure/temperature - 2

    */

    vector<vector<double>> Hx(8, vector<double>(1, 0));

    double P_u = states[2][0];

    vector<vector<double>> a_w({{states[6][0]},{states[7][0]},{states[8][0]+gravity}});

    // double a_x = states[6][0];
    // double a_y = states[7][0];
    // double a_z = states[8][0];

    double q0 = states[9][0];
    double q1 = states[10][0];
    double q2 = states[11][0];
    double q3 = states[12][0];

    double q0_dot = states[13][0];
    double q1_dot = states[14][0];
    double q2_dot = states[15][0];
    double q3_dot = states[16][0];


    vector<vector<double>> a_b = mat_mul(quat2DCM(q0,q1,q2,q3),a_w);

    switch (sensor_id){
        case 3:
        Hx = vector<vector<double>>(6, vector<double>(1, 0));
        Hx[0][0] = a_b[0][0];
        Hx[1][0] = a_b[1][0];
        Hx[2][0] = a_b[2][0];

        Hx[3][0] = 2*(-q0_dot*q1+q1_dot*q0+q2_dot*q3-q3_dot*q2);
        Hx[4][0] = 2*(-q0_dot*q2-q1_dot*q3+q2_dot*q0+q3_dot*q1);
        Hx[5][0] = 2*(-q0_dot*q3+q1_dot*q2-q2_dot*q1+q3_dot*q0);
        break;

        case 5:
        Hx = vector<vector<double>>(3, vector<double>(1, 0));
        Hx[0][0] = a_b[0][0];
        Hx[1][0] = a_b[1][0];
        Hx[2][0] = a_b[2][0];
        break;


        case 2:
        Hx = vector<vector<double>>(2, vector<double>(1, 0));
        Hx[0][0] = P0*pow(((T0-L*P_u)/T0),(gravity/(R_air*L)));
        Hx[1][0] = T0-L*P_u;
        break;
    }
    return Hx;
}

vector<vector<double>> calculateR(const uint sensor_id_){
    vector<vector<double>> R;
    switch (sensor_id_){
        case 3:
        R = vector<vector<double>>(6, vector<double>(6, 0));
        R[0][0] = R[1][1] = R[2][2] = 0.5;
        R[3][3] = R[4][4] = R[5][5] = 0.1;
        break;

        case 5:
        R = vector<vector<double>>(3, vector<double>(3, 0));
        R[0][0] = R[1][1] = R[2][2] = 0.3;
        break;


        case 2:
        R = vector<vector<double>>(2, vector<double>(2, 0));
        R[0][0] = 3;
        R[1][1] = 1;
        break;
    }
    return R;
}


// RK4 for stepping in Update Step
vector<vector<double>> rk4_step_mat(const vector<vector<double>>& y, double dt, const std::function<vector<vector<double>>(const vector<vector<double>>&)> &dydt) {
    vector<vector<double>> k1 = dydt(y);
    vector<vector<double>> y2 = mat_add(y, matrixTimesScaler(dt/2.0, k1));
    vector<vector<double>> k2 = dydt(y2);
    vector<vector<double>> y3 = mat_add(y, matrixTimesScaler(dt/2.0, k2));
    vector<vector<double>> k3 = dydt(y3);
    vector<vector<double>> y4 = mat_add(y, matrixTimesScaler(dt, k3));
    vector<vector<double>> k4 = dydt(y4);
    vector<vector<double>> result = y;
    for (size_t i = 0; i < y.size(); ++i) {
        for (size_t j = 0; j < y[0].size(); ++j) {
            result[i][j] += dt/6.0 * (k1[i][j] + 2*k2[i][j] + 2*k3[i][j] + k4[i][j]);
        }
    }
    return result;
}

vector<double> rk4_step_vec(const vector<double>& y, double dt, const std::function<vector<double>(const vector<double>&)>& dydt) {
    vector<double> k1 = dydt(y);
    vector<double> y2 = vector_add(y, vectorTimesScaler(dt/2.0, k1));
    vector<double> k2 = dydt(y2);
    vector<double> y3 = vector_add(y, vectorTimesScaler(dt/2.0, k2));
    vector<double> k3 = dydt(y3);
    vector<double> y4 = vector_add(y, vectorTimesScaler(dt, k3));
    vector<double> k4 = dydt(y4);
    vector<double> result(y.size());
    for (size_t i = 0; i < y.size(); ++i) {
        result[i] = y[i] + dt/6.0 * (k1[i] + 2*k2[i] + 2*k3[i] + k4[i]);
    }
    return result;
}

// Force Calculation for Update
vector<vector<double>> calculateBodyForces(vector<double> quat, double drag, double thrust, double mass, double gravity_){

    // Calculate the forces acting on the aircraft in the body frame
    vector<vector<double>> R = quat2DCM(quat[0],quat[1],quat[2],quat[3]);
    vector<vector<double>> g_w = {{0},{0},{-gravity_*mass}};

    vector<vector<double>> d = mat_mul(R,{{0},{0},{-drag}});
    vector<vector<double>> t = mat_mul(R,{{0},{0},{thrust}});

    vector<vector<double>> F_w = mat_add(g_w,mat_add(d,t));
    return F_w;
}

// Calculate Acceleration for update
vector<vector<double>> calculateAcceleration(vector<vector<double>> F_b, double m, vector<vector<double>> omega_b, vector<vector<double>> V_b){
    
    // vector<vector<double>> a_rot = {{omega_b[2][0]*V_b[1][0]-omega_b[1][0]*V_b[2][0]},
    //                                 {omega_b[0][0]*V_b[2][0]-omega_b[2][0]*V_b[0][0]},
    //                                 {omega_b[1][0]*V_b[0][0]-omega_b[0][0]*V_b[1][0]}};

    vector<vector<double>> a_b = matrixTimesScaler(1/m, F_b);

    return a_b;
}

// Calculate Rotational Acceleration for Update
vector<vector<double>> calculateRotationalAcceleration(vector<vector<double>> I, vector<vector<double>> omega_b, vector<vector<double>> M_b){
    vector<vector<double>> rot_accel = mat_mul(inverseMatrix(I),mat_add(crossProduct(negative(omega_b),mat_mul(I,omega_b)),M_b));
    return rot_accel;
}



